#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int n, k, m;
    scanf("%d %d %d", &n, &k, &m);

    int t[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &t[i]);
    }
    qsort(t, n, sizeof(int), compare);

    int sum = 0;
    for (int i = 0; i < n; i++) {
        sum += t[i];
    }

    int mx = 0;
    int full = 0;
    while (full <= n && full * sum <= m) {
        int cnt = full * k + full;
        int free_time = m - sum * full;
        for (int i = 0; i < n; i++) {
            int tasks = (n - full < free_time / t[i]) ? n - full : free_time / t[i];
            cnt += tasks;
            free_time -= tasks * t[i];
        }
        if (cnt > mx) {
            mx = cnt;
        }
        full++;
    }
    printf("%d\n", mx);
    return 0;
}
